/**
 * generate-block-atlas.mjs — Stitches individual vanilla block render snapshots
 * into a single sprite sheet + coord JSON for the block picker.
 *
 * INPUT (not committed; generated by `npm run update-snapshots-blocks`):
 *   debugoutput/res/snapshots/block-<name-with-dashes>.png
 *   Snapshots are 3D renders produced by the CLI's `rendervanilla` command.
 *
 * OUTPUT (committed):
 *   public/data/atlases/block-sprites.png   — tiled atlas, TILE_SIZE per cell
 *   public/data/block-atlas.json            — { tileSize, cols, rows, file, blocks }
 *
 * Unlike the item catalog's sprite atlas (which runs on every dlres because
 * item textures are tiny flat PNGs lifted from the resource pack), this
 * script is an occasional/asynchronous build step: rendering every vanilla
 * block via Babylon.js takes an hour+. Once rendered into debugoutput/, this
 * script packs them in ~10 seconds.
 *
 * USAGE
 *   From app/:
 *     node scripts/generate-block-atlas.mjs
 *     node scripts/generate-block-atlas.mjs --tile 96
 *     node scripts/generate-block-atlas.mjs --snapshots <dir>
 *
 * The picker (BlockPickerDialog) loads the committed atlas PNG + JSON via
 * BlockSpriteDatabase and renders each tile through a CSS background-position
 * — one HTTP request for ~800 blocks instead of ~800.
 */

import { existsSync, mkdirSync, readdirSync, readFileSync, writeFileSync } from "fs";
import { join, resolve } from "path";

const DEFAULT_SNAPSHOTS_DIR = "debugoutput/res/snapshots";
const DEFAULT_TILE_SIZE = 64;
const ATLAS_DIR = "public/data/atlases";
const ATLAS_PNG = "public/data/atlases/block-sprites.png";
const ATLAS_JSON = "public/data/block-atlas.json";

// ── Arg parsing ──────────────────────────────────────────────────────────
const args = process.argv.slice(2);
let tileSize = DEFAULT_TILE_SIZE;
let snapshotsDir = DEFAULT_SNAPSHOTS_DIR;
for (let i = 0; i < args.length; i++) {
  if (args[i] === "--tile" && args[i + 1]) {
    tileSize = parseInt(args[++i], 10);
    if (!Number.isFinite(tileSize) || tileSize < 16 || tileSize > 512) {
      console.error(`Invalid --tile ${args[i]} (must be 16..512)`);
      process.exit(2);
    }
  } else if (args[i] === "--snapshots" && args[i + 1]) {
    snapshotsDir = args[++i];
  }
}

// ── Locate inputs ────────────────────────────────────────────────────────
const snapshotsRoot = resolve(snapshotsDir);
if (!existsSync(snapshotsRoot)) {
  console.error(`Snapshots directory not found: ${snapshotsRoot}`);
  console.error("Render snapshots first: npm run update-snapshots-blocks");
  process.exit(1);
}

const files = readdirSync(snapshotsRoot).filter((f) => f.startsWith("block-") && f.endsWith(".png"));
if (files.length === 0) {
  console.error(`No block-*.png files found in ${snapshotsRoot}`);
  console.error("Render snapshots first: npm run update-snapshots-blocks");
  process.exit(1);
}
files.sort();
console.log(`Found ${files.length} block snapshots in ${snapshotsRoot}`);

// ── Load sharp (required) ────────────────────────────────────────────────
let sharp;
try {
  sharp = (await import("sharp")).default;
} catch {
  console.error("sharp is required. Install it: npm install --save-dev sharp");
  process.exit(1);
}

// ── Layout ───────────────────────────────────────────────────────────────
// Snapshot filenames use dashes where the block id uses underscores
// (see updateSnapshots.ts: item.replace(/_/g, "-")).
function fileToBlockId(filename) {
  const base = filename.replace(/^block-/, "").replace(/\.png$/, "");
  return base.replace(/-/g, "_");
}

const cols = Math.ceil(Math.sqrt(files.length));
const rows = Math.ceil(files.length / cols);
const atlasWidth = cols * tileSize;
const atlasHeight = rows * tileSize;

console.log(`Atlas layout: ${cols}×${rows} tiles @ ${tileSize}px = ${atlasWidth}×${atlasHeight}px`);

// ── Pre-process each snapshot ────────────────────────────────────────────
// 1. Trim transparent padding so the block fills the tile.
// 2. Resize to tileSize×tileSize. Blocks are 3D renders, so lanczos/default
//    resize is preferred over nearest (would look jagged when scaled down
//    from e.g. 512→64).
const blocks = {};
const composites = [];
let skipped = 0;

for (let i = 0; i < files.length; i++) {
  const file = files[i];
  const blockId = fileToBlockId(file);
  const x = (i % cols) * tileSize;
  const y = Math.floor(i / cols) * tileSize;
  const fullPath = join(snapshotsRoot, file);

  try {
    const buf = await sharp(fullPath)
      .trim({ background: { r: 0, g: 0, b: 0, alpha: 0 }, threshold: 1 })
      .resize(tileSize, tileSize, { fit: "contain", background: { r: 0, g: 0, b: 0, alpha: 0 } })
      .png()
      .toBuffer();
    composites.push({ input: buf, left: x, top: y });
    blocks[blockId] = { x, y };
  } catch (err) {
    skipped++;
    if (skipped <= 10) {
      console.warn(`  Skipped ${file}: ${err.message}`);
    }
  }

  if ((i + 1) % 100 === 0) {
    console.log(`  Processed ${i + 1}/${files.length}…`);
  }
}

if (skipped > 10) {
  console.warn(`  …and ${skipped - 10} more skipped.`);
}

// ── Composite the final atlas ────────────────────────────────────────────
if (!existsSync(ATLAS_DIR)) {
  mkdirSync(ATLAS_DIR, { recursive: true });
}

console.log(`Compositing ${composites.length} tiles…`);
await sharp({
  create: {
    width: atlasWidth,
    height: atlasHeight,
    channels: 4,
    background: { r: 0, g: 0, b: 0, alpha: 0 },
  },
})
  .composite(composites)
  .png({ compressionLevel: 9 })
  .toFile(ATLAS_PNG);

const atlasSize = readFileSync(ATLAS_PNG).length;

// ── Write coord JSON ─────────────────────────────────────────────────────
const manifest = {
  version: 1,
  generated: new Date().toISOString().split("T")[0],
  tileSize,
  cols,
  rows,
  file: "atlases/block-sprites.png",
  blocks,
};
writeFileSync(ATLAS_JSON, JSON.stringify(manifest));
const jsonSize = Buffer.byteLength(JSON.stringify(manifest));

console.log(`\nWrote ${ATLAS_PNG}  (${(atlasSize / 1024).toFixed(1)} KB)`);
console.log(`Wrote ${ATLAS_JSON} (${(jsonSize / 1024).toFixed(1)} KB, ${Object.keys(blocks).length} blocks)`);
if (skipped > 0) {
  console.log(`Skipped ${skipped} snapshot(s) that failed to process.`);
}
